+import { $internal } from '../common';
+import { createEntity, destroyEntity } from '../entity/entity';
+import type { Entity } from '../entity/types';
+import { getRelationTargets } from '../relation/relation';
+import type { RelationPair } from '../relation/types';
+import { isRelationPair } from '../relation/utils/is-relation';
+import { addTrait, getTrait, hasTrait, removeTrait, setTrait } from '../trait/trait';
+import type { ConfigurableTrait, Trait } from '../trait/types';
+import type { World } from './types';
+
+type Command =
+    | { type: 'spawn'; entity: Entity; traits: ConfigurableTrait[] }
+    | { type: 'destroy'; entity: Entity }
+    | { type: 'add'; entity: Entity; traits: ConfigurableTrait[]; exclusive: boolean }
+    | { type: 'remove'; entity: Entity; traits: (Trait | RelationPair)[] };
+
+type DeferredScope = { commands: Command[] };
+
+function scopes(world: World): DeferredScope[] {
+    return world[$internal].deferredScopes;
+}
+
+function commandsFor(world: World, entity: Entity): Command[] {
+    return scopes(world).flatMap((scope) => scope.commands.filter((command) => command.entity === entity));
+}
+
+export function beginDeferredScope(world: World) {
+    scopes(world).push({ commands: [] });
+}
+
+export function endDeferredScope(world: World) {
+    const scope = scopes(world).pop();
+    if (scope?.commands.length) flushCommands(world, scope.commands);
+}
+
+export function flushDeferredEntity(world: World, entity: Entity) {
+    const pending = commandsFor(world, entity);
+    if (!pending.length) return;
+    for (const scope of scopes(world)) {
+        scope.commands = scope.commands.filter((command) => command.entity !== entity);
+    }
+    flushCommands(world, pending);
+}
+
+/** Projected membership used by Entity#has while commands are pending. */
+export function hasDeferredTrait(world: World, entity: Entity, trait: Trait | RelationPair): boolean | undefined {
+    const commands = commandsFor(world, entity);
+    if (!commands.length) return undefined;
+    let exists = world.has(entity);
+    let result = isRelationPair(trait)
+        ? entity.has(trait)
+        : hasTrait(world, entity, trait as Trait);
+
+    for (const command of commands) {
+        if (command.type === 'spawn') exists = true;
+        if (command.type === 'destroy') exists = false;
+        if (!exists) continue;
+        if (command.type === 'remove') {
+            if (command.traits.some((item) => sameTrait(item, trait))) result = false;
+        }
+        if (command.type === 'add') {
+            for (const item of command.traits) {
+                if (sameTrait(item, trait)) result = !isWildcard(item);
+                if (command.exclusive && isRelationPair(item) && isRelationPair(trait)) {
+                    const a = item[$internal].relation;
+                    const b = trait[$internal].relation;
+                    if (a === b && item[$internal].target !== trait[$internal].target) result = false;
+                }
+            }
+        }
+    }
+    return exists && result;
+}
+
+/** Projected value used by Entity#get while commands are pending. */
+export function getDeferredTrait(world: World, entity: Entity, trait: Trait | RelationPair): unknown {
+    const commands = commandsFor(world, entity);
+    if (!commands.length) return undefined;
+    let value = getTrait(world, entity, trait);
+    for (const command of commands) {
+        if (command.type === 'destroy') return undefined;
+        if (command.type !== 'add') continue;
+        for (const item of command.traits) {
+            if (!sameTrait(item, trait)) continue;
+            if (Array.isArray(item)) value = item[1];
+            else if (isRelationPair(item)) value = item[$internal].params;
+        }
+    }
+    return hasDeferredTrait(world, entity, trait) ? value : undefined;
+}
+
+function sameTrait(a: ConfigurableTrait | Trait | RelationPair, b: Trait | RelationPair) {
+    if (isRelationPair(a) || isRelationPair(b)) {
+        return (
+            isRelationPair(a) &&
+            isRelationPair(b) &&
+            a[$internal].relation === b[$internal].relation &&
+            (a[$internal].target === b[$internal].target || a[$internal].target === '*' || b[$internal].target === '*')
+        );
+    }
+    const trait = Array.isArray(a) ? a[0] : a;
+    return trait === b;
+}
+
+function isWildcard(item: ConfigurableTrait) {
+    return isRelationPair(item) && item[$internal].target === '*';
+}
+
+function applyAdd(world: World, entity: Entity, traits: ConfigurableTrait[], exclusive: boolean) {
+    for (const item of traits) {
+        if (isRelationPair(item)) {
+            const relation = item[$internal].relation;
+            if (exclusive) removeTrait(world, entity, relation('*'));
+            if (item[$internal].target !== '*') {
+                if (entity.has(item)) setTrait(world, entity, item, item[$internal].params, false);
+                else addTrait(world, entity, item);
+            }
+            continue;
+        }
+        const trait = Array.isArray(item) ? item[0] : item;
+        const value = Array.isArray(item) ? item[1] : undefined;
+        if (hasTrait(world, entity, trait)) {
+            if (value !== undefined) setTrait(world, entity, trait, value, false);
+        } else addTrait(world, entity, item);
+    }
+}
+
+function flushCommands(world: World, commands: Command[]) {
+    const ctx = world[$internal];
+    if (ctx.isDeferredFlushing) return;
+    ctx.isDeferredFlushing = true;
+    try {
+        for (const command of commands) {
+            if (command.type === 'destroy' && command.entity === ctx.worldEntity) {
+                throw new Error('Koota: The world entity cannot be destroyed with deferred commands.');
+            }
+            if (command.type === 'spawn') continue;
+            if (!world.has(command.entity)) continue;
+            if (command.type === 'destroy') destroyEntity(world, command.entity);
+            else if (command.type === 'remove') removeTrait(world, command.entity, ...command.traits);
+            else applyAdd(world, command.entity, command.traits, command.exclusive);
+        }
+        // Reserved spawned entities become visible only after their commands have run.
+        for (const command of commands) {
+            if (command.type !== 'spawn') continue;
+            const destroyed = commands.some((other) => other.type === 'destroy' && other.entity === command.entity);
+            if (destroyed) {
+                if (world.has(command.entity)) destroyEntity(world, command.entity);
+                continue;
+            }
+            if (!world.has(command.entity)) continue;
+            removeTrait(world, command.entity, (awaitedExcluded as Trait));
+            applyAdd(world, command.entity, command.traits, false);
+        }
+    } finally {
+        ctx.isDeferredFlushing = false;
+    }
+}
+
+// Kept here to avoid exporting the internal query trait through the deferred API.
+import { IsExcluded as awaitedExcluded } from '../query/query';
+
+export function createDeferred(world: World) {
+    const enqueue = (command: Command) => scopes(world)[scopes(world).length - 1]!.commands.push(command);
+    return {
+        spawn(...traits: ConfigurableTrait[]) {
+            const entity = createEntity(world, awaitedExcluded);
+            enqueue({ type: 'spawn', entity, traits });
+            return entity;
+        },
+        destroy(entity: Entity) {
+            enqueue({ type: 'destroy', entity });
+        },
+        add(entity: Entity, ...traits: ConfigurableTrait[]) {
+            enqueue({ type: 'add', entity, traits, exclusive: false });
+        },
+        remove(entity: Entity, ...traits: (Trait | RelationPair)[]) {
+            enqueue({ type: 'remove', entity, traits });
+        },
+        addExclusive(entity: Entity, ...traits: ConfigurableTrait[]) {
+            enqueue({ type: 'add', entity, traits, exclusive: true });
+        },
+        flush() {
+            const root = scopes(world)[0]!;
+            const commands = root.commands.splice(0);
+            if (commands.length) flushCommands(world, commands);
+        },
+    };
+}
